const calculateCartTotals = (items, promoCode = null) => {
  // Calcul du sous-total HT
  const subtotalHT = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  // Application de la remise automatique (10% si > 100€)
  let discount = 0;
  if (subtotalHT > 100) {
    discount = subtotalHT * 0.10;
  }

  // Application du code promo (20%)
  let promoDiscount = 0;
  if (promoCode === 'CAMEROUN20') {
    promoDiscount = subtotalHT * 0.20;
  }

  const subtotalAfterDiscount = subtotalHT - discount - promoDiscount;

  // Calcul des frais de livraison
  let shippingFees = 0;
  if (subtotalAfterDiscount < 50) {
    shippingFees = 5;
  }

  // Calcul de la TVA (20% sur le sous-total après remise, hors livraison)
  const tva = subtotalAfterDiscount * 0.20;

  // Total final (TTC)
  const totalTTC = subtotalAfterDiscount + tva + shippingFees;

  return {
    subtotalHT: subtotalHT.toFixed(2),
    volumeDiscount: discount.toFixed(2),
    promoDiscount: promoDiscount.toFixed(2),
    subtotalAfterDiscount: subtotalAfterDiscount.toFixed(2),
    shippingFees: shippingFees.toFixed(2),
    tva: tva.toFixed(2),
    totalTTC: totalTTC.toFixed(2),
    promoApplied: promoCode === 'CAMEROUN20'
  };
};
```
